{"output": "=== DAYAH ===
# =============================================================================
# Dayah LitWorks - nginx reverse proxy
# Proxies dayah.paragu-ai.com -> paragu-ai.com/s/es/dayah-litworks
# =============================================================================


diff --git a/nginx.conf b/nginx.conf
index e707379..[REDACTED_PHONE]
--- a/nginx.conf
+++ b/nginx.conf
@@ -24,13 +24,16 @@ server {
     add_header Referrer-Policy "strict-origin-when-cross-origin" always;
     add_header Strict-Transport-Security "max-age=63072000; includeSubDomains; preload" always;

-    # Root: redirect / to PAB's dayah-litworks Spanish site
+    # Root: rewrite / to /s/es/dayah-litworks (no trailing slash)
+    # Other paths: /faq → /s/es/dayah-litworks/faq
     location / {
-        proxy_pass http://paragu_ai_backend/s/es/dayah-litworks;
+        rewrite ^/$ /s/es/dayah-litworks break;
+        rewrite ^/(.+)$ /s/es/dayah-litworks/$1 break;
+        proxy_pass http://paragu_ai_backend;
         proxy_http_version 1.1;
         proxy_set_header Upgrade $http_upgrade;
         proxy_set_header Connection 'upgrade';
-        proxy_set_header Host $host;", "exit_code": 0, "error": null}

